CREATE TABLE executions (
    id SERIAL PRIMARY KEY,
    test_case_id INT NOT NULL REFERENCES test_cases(id) ON DELETE CASCADE,
    user_id INT REFERENCES users(id), -- Nullable if run by CI/CD bot
    status execution_status NOT NULL DEFAULT 'IN_PROGRESS',
    executed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    duration_seconds INT,
    error_message TEXT,
    screenshot_url VARCHAR(500), -- Link to artifact storage
    build_number VARCHAR(100), -- Useful for CI/CD correlation
    metadata JSONB -- Flexible storage for extra context (browser version, device, etc.)
);
CREATE INDEX idx_executions_test ON executions(test_case_id);
CREATE INDEX idx_executions_date ON executions(executed_at);
CREATE INDEX idx_executions_status ON executions(status);
